const res = await fetch('https://api.github.com/repos/dpearson2699/swift-ios-skills/contents/skills?ref=main');
const arr = await res.json();
const needles = ['health','watch','workout','activity','widget','background','core-ml','apple-on-device','swiftdata','swift-concurrency','swift-testing','swift-security','core-motion','app-intents','push','metric','natural-language','network','keychain','cloudkit','swiftui','storekit','foundation','permission'];
const names = arr.map(x=>x.name).filter(n => needles.some(k => n.includes(k))).sort();
nodeRepl.write(names.join('\n'));
